    def inv(self, tensordict: TensorDictBase) -> TensorDictBase:
        """Applies the inverse transform to a tensordict.

        This method will be called whenever a transform is applied to a
        tensordict that is part of a trajectory that is being replayed.
        """
        if not self.invertible:
            raise RuntimeError(
                f"Transform {self} is not invertible. "
                f"To make it invertible, set the `invertible` attribute to True "
                f"and implement the `_inv_apply_transform` method."
            )
        for in_key, out_key in zip(self.in_keys_inv, self.out_keys_inv):
            if in_key in tensordict.keys():
                tensordict.set(out_key, self._inv_apply_transform(tensordict.get(in_key)))
        return tensordict

    def forward(self, tensordict: TensorDictBase) -> TensorDictBase:
        """Reads the input tensordict, and for the selected keys, applies the transform."""
        for in_key, out_key in zip(self.in_keys, self.out_keys):
            if in_key in tensordict.keys():
                tensordict.set(out_key, self._apply_transform(tensordict.get(in_key)))
        return tensordict

