    def inv(self, tensordict: TensorDictBase) -> TensorDictBase:
        """Applies the inverse transform to the tensordict.

        For each in_key/out_key pair, the inverse transform will be applied to the
        out_key tensor and the result will be written in in_key_inv.
        For each in_key_inv/out_key_inv pair, the inverse transform will be applied to the
        out_key_inv tensor and the result will be written in in_key_inv.

        """
        if not self.invertible:
            raise RuntimeError(f"{self.__class__.__name__} is not invertible.")
        for in_key, out_key in zip(self.in_keys, self.out_keys):
            if out_key in tensordict.keys():
                tensordict.set(
                    self.in_keys_inv[self.out_keys.index(out_key)],
                    self._inv_apply_transform(tensordict.get(out_key)),
                )
        for in_key_inv, out_key_inv in zip(self.in_keys_inv, self.out_keys_inv):
            if out_key_inv in tensordict.keys():
                tensordict.set(
                    in_key_inv,
                    self._inv_apply_transform(tensordict.get(out_key_inv)),
                )
        return tensordict

